import base64
import json

def decode_jwt(token):
    try:
        header, payload, signature = token.split('.')
        # Fix padding for base64
        payload_decoded = base64.urlsafe_b64decode(payload + '=' * (4 - len(payload) % 4))
        return json.loads(payload_decoded)
    except Exception as e:
        return {"error": str(e)}

